import api from "../../components/api";
import { CheckEmailReq, CheckEmailRes, LoginReq, LoginRes } from "./loginTypes";

const login = async (request: LoginReq): Promise<LoginRes> => {
	const response = await api.post("/v1/user/session", request);
	return response.data;
};

const logout = async (): Promise<void> => {
	await api.delete("/v1/user//session");
};

const isLogged = async (): Promise<void> => {
	await api.get("/v1/user");
};

const checkEmail = async (request: CheckEmailReq): Promise<CheckEmailRes> => {
	const response = await api.get("/v1/user/check-email", { params: request });
	return response.data;
};

const loginService = {
	login,
	logout,
	isLogged,
	checkEmail,
};

export default loginService;
